create table dh_day (ts timestamp);
insert into dh_day (id, ts) values
	(1,1704067201),
	(2,1704110400),
	(3,1704153605),
	(4,1704239999),
	(5,1704240000),
	(6,1704283200);


select count(*) as cnt, date_histogram(ts, {fixed_interval='3600s'}) as dh from dh_hour group by dh order by dh asc;
select count(*) as cnt, date_histogram(ts, {fixed_interval='1h'}) as dh from dh_hour group by dh order by dh asc;
select count(*) as cnt, date_histogram(ts, {fixed_interval='60m'}) as dh from dh_hour group by dh order by dh asc;
select count(*) as cnt, date_histogram(ts, {fixed_interval='hour'}) as dh from dh_hour group by dh order by dh asc;


select count(*) as cnt, date_histogram(ts, {fixed_interval='minute'}) as dh from dh_minute group by dh order by dh asc;
select count(*) as cnt, date_histogram(ts, {fixed_interval='2m'}) as dh from dh_minute group by dh order by dh asc;
select count(*) as cnt, date_histogram(ts, {fixed_interval='3h'}) as dh from dh_hour group by dh order by dh asc;


select count(*) as cnt, date_histogram(ts, {fixed_interval='day'}) as dh from dh_day group by dh order by dh asc;
select count(*) as cnt, date_histogram(ts, {fixed_interval='5d'}) as dh from dh_day group by dh order by dh asc;

create table dh_tz (ts timestamp);
insert into dh_tz (id, ts) values
	(1,1704061800),
	(2,1704144600),
	(3,1704148200),
	(4,1704155400);


select count(*) as cnt, date_histogram(ts, {calendar_interval='day'}) as dh from dh_tz group by dh order by dh asc;
select count(*) as cnt, date_histogram(ts, {calendar_interval='day', calendar_interval_time_zone='Asia/Novosibirsk'}) as dh from dh_tz group by dh order by dh asc;
select count(*) as cnt, date_histogram(ts, {calendar_interval='day', calendar_interval_offset='3h'}) as dh from dh_tz group by dh order by dh asc;
select count(*) as cnt, date_histogram(ts, {calendar_interval='day', calendar_interval_offset='10800s'}) as dh from dh_tz group by dh order by dh asc;

drop table dh_minute;
drop table dh_hour;
drop table dh_day;
drop table dh_tz;
